// Handle Python service failure gracefully
const res = $input.first().json;

// Check for HTTP error or service unavailable
if (res.error || res.statusCode >= 400) {
  console.error('[treasury] Python service failed:', JSON.stringify(res));
  // Try to get last known snapshot from Supabase as fallback
  return [{ json: { _calculation_failed: true, error: res.error || res.detail || 'Unknown error' } }];
}

// Validate required fields exist
const required = ['cash', 'burn_rate', 'runway_months', 'alert_level'];
const missing = required.filter(f => res[f] === undefined || res[f] === null);
if (missing.length > 0) {
  console.error('[treasury] Missing fields:', missing);
  return [{ json: { _calculation_failed: true, error: `Missing fields: ${missing.join(', ')}` } }];
}

// Add warnings from Python service
const warnings = res.warnings || [];
if (res.data_freshness === 'stale') {
  warnings.push('Using stale bank balance — live API was unavailable');
}

console.log(`[treasury] Snapshot OK: runway=${res.runway_months}mo alert=${res.alert_level}`);
return [{ json: { ...res, _calculation_failed: false, _warnings: warnings } }];

const current  = $('Handle Snapshot Result').first().json;
const snapshots = $('Supabase — Fetch Previous Snapshot').all().map(i => i.json);
const prev = snapshots[1] || snapshots[0] || null;

const runwayChange = prev
  ? parseFloat(current.runway_months) - parseFloat(prev.runway_months)
  : 0;

const changeDir = runwayChange > 0.1 ? 'improved' : runwayChange < -0.1 ? 'degraded' : 'stable';

return [{
  json: {
    ...current,
    prev_runway_months: prev?.runway_months || null,
    prev_burn_rate: prev?.burn_rate || null,
    runway_change: parseFloat(runwayChange.toFixed(1)),
    runway_change_direction: changeDir
  }
}];

// Build treasury explanation prompt for Claude
// Only called when alert level is WARNING or CRITICAL
const snap = $input.first().json;
const curr = snap.currency || 'USD';
const fmt  = n => parseFloat(n || 0).toLocaleString('en-US', { maximumFractionDigits: 0 });

const prevRunwayLine = snap.prev_runway_months
  ? `Previous runway: ${snap.prev_runway_months} months`
  : 'No previous snapshot for comparison';

const warningsLine = (snap._warnings || []).length > 0
  ? `DATA QUALITY WARNINGS: ${snap._warnings.join('; ')}`
  : '';

const prompt = `You are a CFO advisor speaking directly to a founder. Be direct. No corporate language.

TREASURY SNAPSHOT
Cash: ${curr} ${fmt(snap.cash)}
Monthly burn: ${curr} ${fmt(snap.burn_rate)}
Projected revenue (30d): ${curr} ${fmt(snap.projected_revenue)}
Runway: ${snap.runway_months} months
Alert level: ${snap.alert_level}
Safe ad/growth budget this month: ${curr} ${fmt(snap.safe_budget)}
Runway trend: ${snap.runway_change_direction} (${snap.runway_change > 0 ? '+' : ''}${snap.runway_change} months vs last check)
${prevRunwayLine}
${warningsLine}

OUTPUT in this exact format:
SITUATION:
[1-2 sentences. Specific numbers. Explain the runway situation and ONE primary cause.]

RISK:
[1 sentence. What concretely happens if this trajectory continues? Name a date or threshold.]

ACTION:
1. [Most impactful action → estimated +X months runway or $X saved]
2. [Second action → impact]
3. [Third action if relevant → impact]

IMPORTANT: The numbers you cite MUST match the snapshot above. Do not invent figures.`;

return [{ json: { ...snap, _treasury_prompt: prompt } }];

const snap     = $('Build Treasury Explanation Prompt').first().json;
const validated = $input.first().json;
const curr     = snap.currency || 'USD';
const fmt      = n => parseFloat(n || 0).toLocaleString('en-US', { maximumFractionDigits: 0 });

// Fall back to raw if validation failed
const explanation = validated.valid
  ? validated.output
  : $('Claude — Treasury Explanation').first().json.content?.[0]?.text || 'Analysis unavailable.';

const emoji = snap.alert_level === 'CRITICAL' ? '🚨' : '⚠️';
const trendEmoji = snap.runway_change_direction === 'improved' ? '📈' : snap.runway_change_direction === 'degraded' ? '📉' : '➡️';

const freshnessBadge = snap.data_freshness === 'stale' ? ' _(stale data)_' : '';

const message = [
  `${emoji} *Treasury ${snap.alert_level} — ${snap.runway_months} months runway*${freshnessBadge}`,
  '',
  `${trendEmoji} *${snap.runway_change_direction.charAt(0).toUpperCase() + snap.runway_change_direction.slice(1)}* vs last check (${snap.runway_change > 0 ? '+' : ''}${snap.runway_change} mo)`,
  `💰 Cash: *${curr} ${fmt(snap.cash)}*  ·  Burn: ${curr} ${fmt(snap.burn_rate)}/mo  ·  Safe budget: ${curr} ${fmt(snap.safe_budget)}`,
  '',
  explanation,
  '',
  ...(validated.warnings?.length ? [`_Warnings: ${validated.warnings.join(' | ')}_`] : [])
].join('\n');

return [{ json: { ...snap, slack_message: message, explanation } }];

// Healthy snapshot — no alert needed, but log for the brief
const snap = $('Enrich with Trend Data').first().json;
const curr = snap.currency || 'USD';
const fmt  = n => parseFloat(n || 0).toLocaleString('en-US', { maximumFractionDigits: 0 });
console.log(`[treasury] ${snap.alert_level}: runway=${snap.runway_months}mo cash=${curr}${fmt(snap.cash)}`);
// No Slack message — healthy is quiet
return [{ json: { skipped_alert: true, reason: 'HEALTHY — no alert needed', snapshot: snap } }];
